import torch
import torch.nn as nn
import esm

class SimpleRegressionHead(nn.Module):
    """Standalone regression head for pre-extracted embeddings."""
    def __init__(self, input_dim, hidden_dim=512, dropout=0.2):
        super().__init__()
        self.head = nn.Sequential(
            nn.Linear(input_dim, hidden_dim),
            nn.GELU(),
            nn.BatchNorm1d(hidden_dim),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, hidden_dim),
            nn.GELU(),
            nn.BatchNorm1d(hidden_dim),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, hidden_dim // 2),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim // 2, 1)
        )

    def forward(self, x):
        return self.head(x).squeeze(-1)


class EnsembleRegressionHead(nn.Module):
    """Ensemble of multiple heads."""
    def __init__(self, input_dim, hidden_dim=512, dropout=0.2, n_heads=5):
        super().__init__()
        self.heads = nn.ModuleList([
            SimpleRegressionHead(input_dim, hidden_dim, dropout)
            for _ in range(n_heads)
        ])

    def forward(self, x):
        preds = [h(x) for h in self.heads]
        return torch.stack(preds, dim=0).mean(dim=0)

    def forward_all(self, x):
        """Return all head predictions."""
        return [h(x) for h in self.heads]
